import{_ as o,I as r,o as e,c as n,at as s,J as l}from"./chunks/framework.DYZFTu11.js";const f=JSON.parse('{"title":"归家者·彩璃","description":"","frontmatter":{},"headers":[],"relativePath":"zh_cn/characters/caili.md","filePath":"zh_cn/characters/caili.md","lastUpdated":1773554418000}'),h={name:"zh_cn/characters/caili.md"};function g(d,a,c,p,b,u){const t=r("NolebaseGitContributors"),i=r("NolebaseGitChangelog");return e(),n("div",null,[a[0]||(a[0]=s('<h1 id="归家者·彩璃" tabindex="-1">归家者·彩璃 <a class="header-anchor" href="#归家者·彩璃" aria-label="Permalink to “归家者·彩璃”">​</a></h1><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to “基本信息”">​</a></h2><ul><li><strong>姓名</strong>: 彩璃</li><li><strong>代号</strong>: 归家者</li><li><strong>身份</strong>: 外来星系流浪科学家，超空间物理学专家</li><li><strong>目标</strong>: 制造超空间引擎，返回故乡</li><li><strong>性别</strong>: 女</li><li><strong>当前状态</strong>: 隐居于Sol-5星球</li><li><strong>Tag</strong>: 角色、科学家、流浪者</li></ul><h2 id="设定档案" tabindex="-1">设定档案 <a class="header-anchor" href="#设定档案" aria-label="Permalink to “设定档案”">​</a></h2><h3 id="性格测试-mbti" tabindex="-1">性格测试 (MBTI) <a class="header-anchor" href="#性格测试-mbti" aria-label="Permalink to “性格测试 (MBTI)”">​</a></h3><p><strong>ESFJ 尽责的守护者</strong></p><ul><li><strong>外向热情 (E)</strong>: 即使身处异乡，依然保持着对新环境的好奇心和适应力，愿意与他人交流合作。</li><li><strong>务实感性 (S)</strong>: 虽然来自截然不同的星系，但迅速接受了&quot;至少物理原则没变&quot;的现实，专注于可行的技术方案。</li><li><strong>情理兼顾 (F)</strong>: 在确保自身返乡目标的同时，依然愿意帮助星溯等需要帮助的人，用实际行动回报他人的协助。</li><li><strong>计划周密 (J)</strong>: 对返乡有着清晰的规划和执行路线，每一步都经过深思熟虑，绝不冒险行事。</li></ul><h3 id="核心特质" tabindex="-1">核心特质 <a class="header-anchor" href="#核心特质" aria-label="Permalink to “核心特质”">​</a></h3><ul><li><strong>坚定的目标导向</strong>: 将返乡视为人生唯一且最高优先级的目标，愿意承担一切必要或非必要的付出。</li><li><strong>灵活的适应能力</strong>: 面对完全陌生的星系文明（灵裔等设定）从最初的震撼中迅速恢复，找到了生存与发展的方向。</li><li><strong>精明的生存智慧</strong>: 深知自己掌握的知识价值，在被双方势力盯上的情况下依然能够巧妙周旋，保全自身。</li><li><strong>知恩图报</strong>: 对于星溯协助收集超空间引擎材料的帮助，不仅透露关键情报，还赠予航天器和武器作为答谢。</li></ul><h3 id="兴趣爱好" tabindex="-1">兴趣爱好 <a class="header-anchor" href="#兴趣爱好" aria-label="Permalink to “兴趣爱好”">​</a></h3><ul><li><strong>超空间物理</strong>: 💙💙💙💙💙 (8/8) (这是她回家的唯一希望)</li><li><strong>跨文明比较研究</strong>: 💙💙💙💙 (5/8) (对SOL星系的独特设定充满研究兴趣)</li><li><strong>贸易/生意</strong>: 💛💛💛 (3/8) (为生存所需，在阿尔法星卖水维持生计)</li><li><strong>隐居生活</strong>: 💚💚💚 (3/8) (为了避开追捕而不得已的选择)</li></ul><h2 id="背景故事" tabindex="-1">背景故事 <a class="header-anchor" href="#背景故事" aria-label="Permalink to “背景故事”">​</a></h2><p><strong>&quot;无论这个星系有多么奇特，无论要付出多少代价，我一定要回到我的家。&quot;</strong></p><p>彩璃来自一个遥远的外来星系，因某种未知的原因流浪到了SOL星系。作为一名超空间物理学专家，她本应能够轻松返回故乡，但这个星系的特殊性——尤其是<strong>灵裔</strong>的存在和独特的物理-灵能混合体系——让她深感震撼。</p><p>最初的震惊过后，彩璃冷静地确认了一个关键事实：<strong>基础物理原则并未改变</strong>。这意味着超空间引擎在理论上依然可行。她迅速调整了心态，开始着手准备返乡所需的一切——材料、设备、资源。</p><h3 id="意外的风波" tabindex="-1">意外的风波 <a class="header-anchor" href="#意外的风波" aria-label="Permalink to “意外的风波”">​</a></h3><p>然而，她的科学知识和能力很快引起了注意。无论是欧加斯财团还是灵裔帝国，都对这位&quot;掌握未知技术的外来者&quot;产生了浓厚的兴趣。更糟糕的是，她在α星通过出售水资源维持生计的行为，被财团认定为&quot;非法水资源交易&quot;——在资源高度管控的财团统治下，这被视为严重的犯罪行为。</p><p>一夜之间，彩璃从一个默默无闻的流浪者变成了被双方势力重点关注、被财团通缉的&quot;危险人物&quot;。</p><div class="tip custom-block"><p class="custom-block-title">荒谬的罪名</p><p>在阿尔法星卖水竟然成为被通缉的理由——这听起来荒谬至极，但在欧加斯财团的统治逻辑下却完全合理：水资源是战略物资，任何未经授权的水交易都被视为对财团权威的挑战，必须被严厉打击。</p><p>这正是财团统治荒谬性与残酷性的缩影。</p></div><h3 id="藏匿于sol-5" tabindex="-1">藏匿于Sol-5 <a class="header-anchor" href="#藏匿于sol-5" aria-label="Permalink to “藏匿于Sol-5”">​</a></h3><p>为了躲避追捕，彩璃选择隐居在<strong>Sol-5</strong>——一颗相对偏远且资源贫瘠的星球。在这里，她继续着超空间引擎的研究与制造工作，同时小心翼翼地避开财团和灵裔的追踪。</p><p>她深知，自己脑中的知识既是最大的财富，也是最危险的负担。只有成功制造出引擎，离开这个危险的星系，她才能真正获得安全。</p><h3 id="与星溯的邂逅" tabindex="-1">与星溯的邂逅 <a class="header-anchor" href="#与星溯的邂逅" aria-label="Permalink to “与星溯的邂逅”">​</a></h3><p>在隐居期间，彩璃意外地与正在寻找家人线索的星溯取得了联系。起初，两人因为目标和立场的不同而产生了分歧，但通过深入的交流，她们化解了误会，并达成了互利的合作。</p><p>星溯协助彩璃收集超空间引擎所需的稀有材料——这些材料在Sol-5及周边区域难以获取，但对于星溯这样有着财团背景和战斗经验的人来说，获取途径要多得多。</p><p>作为回报，彩璃向星溯透露了她所掌握的关键情报——包括关于星源和灵裔的一些秘密，以及一些她在流浪途中观察到的财团与灵裔之间微妙关系的线索。此外，她还赠予星溯一艘<strong>小型航天器</strong>和一把<strong>便携式激光武器</strong>，这些装备对于星溯接下来的旅程至关重要。</p><h3 id="各自的征途" tabindex="-1">各自的征途 <a class="header-anchor" href="#各自的征途" aria-label="Permalink to “各自的征途”">​</a></h3><p>在完成了引擎的最后准备后，彩璃与星溯道别。两人踏上了各自的征途——星溯继续寻找失踪的家人，而彩璃则准备启动引擎，穿越星海，返回遥远的故乡。</p><p>两个同样在异乡挣扎、同样渴望与家人团聚的灵魂，在短暂的交集后，再次分道扬镳。但她们都知道，在这场漫长的旅程中，她们并不孤单。</p><h2 id="能力与技术" tabindex="-1">能力与技术 <a class="header-anchor" href="#能力与技术" aria-label="Permalink to “能力与技术”">​</a></h2><h3 id="核心能力" tabindex="-1">核心能力 <a class="header-anchor" href="#核心能力" aria-label="Permalink to “核心能力”">​</a></h3><ul><li><strong>超空间物理学</strong>: 掌握来自外来星系的先进超空间理论，这是她返乡的唯一依靠。</li><li><strong>跨文明适应力</strong>: 能够迅速理解并适应全新的文明体系，即使面对灵裔这样的&quot;不可思议存在&quot;也能保持冷静。</li><li><strong>生存智慧</strong>: 在被双方势力追捕的情况下，依然能够巧妙隐藏，维持研究工作。</li><li><strong>工程制造</strong>: 具备从理论到实践的完整能力，能够独立设计并制造超空间引擎。</li></ul><h3 id="知识储备" tabindex="-1">知识储备 <a class="header-anchor" href="#知识储备" aria-label="Permalink to “知识储备”">​</a></h3><p>彩璃脑中的知识对于SOL星系的各方势力来说都是无价之宝：</p><ul><li><strong>外来星系的科技体系</strong>: 可能领先于SOL星系数十年甚至数百年。</li><li><strong>超空间航行理论</strong>: 如果被财团或灵裔获取，可能彻底改变星系的权力格局。</li><li><strong>跨星系观察</strong>: 她对SOL星系特殊性的理解，可能揭示一些连本地居民都未曾意识到的秘密。</li></ul><p>这些知识让她成为各方势力觊觎的对象，但也是她唯一的护身符——只要她活着，知识就有价值；只要知识有价值，她就有谈判的筹码。</p><h2 id="人际关系" tabindex="-1">人际关系 <a class="header-anchor" href="#人际关系" aria-label="Permalink to “人际关系”">​</a></h2><h3 id="星溯" tabindex="-1">星溯 <a class="header-anchor" href="#星溯" aria-label="Permalink to “星溯”">​</a></h3><ul><li><strong>关系</strong>: 互助合作者，短暂的旅伴</li><li><strong>评价</strong>: &quot;一个坚韧而可靠的战士。她对家人的执着让我看到了自己的影子。&quot;</li><li><strong>互动</strong>: 从最初的分歧到相互理解,再到互利合作,最终各自踏上征途。彩璃对星溯的帮助表达了真诚的感激,并给予了实质性的回报。</li></ul><h3 id="欧加斯财团" tabindex="-1">欧加斯财团 <a class="header-anchor" href="#欧加斯财团" aria-label="Permalink to “欧加斯财团”">​</a></h3><ul><li><strong>关系</strong>: 被通缉者</li><li><strong>态度</strong>: 警惕与回避。她深知财团的贪婪,绝不会让自己的知识落入他们手中。</li></ul><h3 id="灵裔帝国" tabindex="-1">灵裔帝国 <a class="header-anchor" href="#灵裔帝国" aria-label="Permalink to “灵裔帝国”">​</a></h3><ul><li><strong>关系</strong>: 被关注者</li><li><strong>态度</strong>: 复杂。一方面对灵裔的存在感到震撼,另一方面意识到他们对自己的知识同样感兴趣。保持距离是最好的选择。</li></ul><h2 id="象征意义" tabindex="-1">象征意义 <a class="header-anchor" href="#象征意义" aria-label="Permalink to “象征意义”">​</a></h2><h3 id="异乡人的孤独" tabindex="-1">异乡人的孤独 <a class="header-anchor" href="#异乡人的孤独" aria-label="Permalink to “异乡人的孤独”">​</a></h3><p>彩璃的存在象征着每一个身处异乡、渴望回家的灵魂。无论这个世界多么奇特,无论周围的人多么不同,家的召唤永远是最强烈的。</p><h3 id="知识的双刃剑" tabindex="-1">知识的双刃剑 <a class="header-anchor" href="#知识的双刃剑" aria-label="Permalink to “知识的双刃剑”">​</a></h3><p>她的遭遇揭示了一个残酷的真相：在一个充满冲突的世界里,知识既是力量,也是诅咒。掌握了太多秘密的人,往往会成为被猎杀的对象。</p><h3 id="目标的纯粹性" tabindex="-1">目标的纯粹性 <a class="header-anchor" href="#目标的纯粹性" aria-label="Permalink to “目标的纯粹性”">​</a></h3><p>与那些在战争、权力、复仇中挣扎的人不同,彩璃的目标异常纯粹——回家。这种纯粹性让她在复杂的局势中保持了清醒,也让她能够做出最理性的判断。</p><h2 id="未来的可能" tabindex="-1">未来的可能 <a class="header-anchor" href="#未来的可能" aria-label="Permalink to “未来的可能”">​</a></h2><p>虽然彩璃的故事看似已经结束——她制造出了引擎,准备启程返乡——但她的影响可能远未终结：</p><ul><li>她留给星溯的情报,可能成为揭开某些秘密的关键线索</li><li>她的航天器和武器,将在星溯未来的冒险中发挥重要作用</li><li>她对SOL星系的观察和理解,可能在未来以某种方式被揭示</li><li>她是否真的能够成功返乡?还是会在途中遭遇新的变故?</li></ul><p><strong>归家者的故事,或许还远未结束。</strong></p><hr><p><em>&quot;每个流浪者都渴望回家。但只有真正踏上归途的人,才能理解那条路有多么漫长。&quot;</em></p>',56)),l(t),l(i)])}const _=o(h,[["render",g]]);export{f as __pageData,_ as default};
